const level = $json.level || 'info';
const message = $json.message || '';
const traceId = $json.traceId || 'no-trace';
const workflow = $json.workflow || 'unknown';
const timestamp = new Date().toISOString();
const meta = $json.meta || {};

const logEntry = { timestamp, level, traceId, workflow, message, meta };

const logLevels = { debug: 0, info: 1, warn: 2, error: 3 };
const currentLevel = logLevels[$env.LOG_LEVEL?.toLowerCase() ?? 'info'] ?? 1;

if (logLevels[level] >= currentLevel) {
  console.log(JSON.stringify(logEntry));
}

return [{ json: { ...$input.item.json, logged: true } }];
